import React, { useState } from 'react';
import { Link, useLocation } from 'react-router-dom';
import {
  Drawer,
  List,
  ListItem,
  ListItemIcon,
  ListItemText,
  Box,
  useTheme,
  Typography,
  Divider,
  IconButton,
  Tooltip,
} from '@mui/material';
import {
  HomeIcon,
  BriefcaseIcon,
  UserGroupIcon,
  ChartBarIcon,
  CogIcon,
  DocumentTextIcon,
  VideoCameraIcon,
  UserCircleIcon,
  ChevronLeftIcon,
  ChevronRightIcon,
} from '@heroicons/react/24/outline';
import { motion, AnimatePresence } from 'framer-motion';
import { useAuth } from '../contexts/AuthContext';
import AnimatedContainer from './AnimatedContainer';

const drawerWidth = 240;
const collapsedWidth = 64;

const Sidebar: React.FC = () => {
  const theme = useTheme();
  const location = useLocation();
  const { user } = useAuth();
  const [isCollapsed, setIsCollapsed] = useState(false);

  const menuItems = [
    {
      text: 'Dashboard',
      icon: <HomeIcon className="h-5 w-5" />,
      path: user?.role === 'APPLICANT' ? '/applicant/dashboard' : '/admin/dashboard',
      roles: ['ADMIN', 'RECRUITER', 'APPLICANT'],
    },
    {
      text: 'Jobs',
      icon: <BriefcaseIcon className="h-5 w-5" />,
      path: '/jobs',
      roles: ['ADMIN', 'RECRUITER', 'APPLICANT', null],
    },
    {
      text: 'Profile',
      icon: <UserCircleIcon className="h-5 w-5" />,
      path: '/applicant/profile',
      roles: ['APPLICANT'],
    },
    {
      text: 'Applications',
      icon: <DocumentTextIcon className="h-5 w-5" />,
      path: '/applicant/apply/:jobId',
      roles: ['APPLICANT'],
    },
    {
      text: 'Interviews',
      icon: <VideoCameraIcon className="h-5 w-5" />,
      path: '/applicant/interview/:applicationId',
      roles: ['APPLICANT'],
    },
    {
      text: 'Candidates',
      icon: <UserGroupIcon className="h-5 w-5" />,
      path: '/admin/candidates',
      roles: ['ADMIN', 'RECRUITER'],
    },
    {
      text: 'Analytics',
      icon: <ChartBarIcon className="h-5 w-5" />,
      path: '/admin/analytics',
      roles: ['ADMIN'],
    },
    {
      text: 'Settings',
      icon: <CogIcon className="h-5 w-5" />,
      path: '/admin/settings',
      roles: ['ADMIN'],
    },
  ];

  const filteredMenuItems = menuItems.filter((item) =>
    item.roles.includes(user?.role || null)
  );

  return (
    <Drawer
      variant="permanent"
      sx={{
        width: isCollapsed ? collapsedWidth : drawerWidth,
        flexShrink: 0,
        transition: theme.transitions.create('width', {
          easing: theme.transitions.easing.sharp,
          duration: theme.transitions.duration.leavingScreen,
        }),
        '& .MuiDrawer-paper': {
          width: isCollapsed ? collapsedWidth : drawerWidth,
          boxSizing: 'border-box',
          backgroundColor: 'background.paper',
          borderRight: `1px solid ${theme.palette.divider}`,
          boxShadow: '2px 0 8px rgba(0,0,0,0.05)',
          transition: theme.transitions.create('width', {
            easing: theme.transitions.easing.sharp,
            duration: theme.transitions.duration.leavingScreen,
          }),
          overflowX: 'hidden',
        },
      }}
    >
      <Box sx={{ overflow: 'auto', p: 2 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
          <AnimatePresence>
            {!isCollapsed && (
              <motion.div
                initial={{ opacity: 0, x: -20 }}
                animate={{ opacity: 1, x: 0 }}
                exit={{ opacity: 0, x: -20 }}
                transition={{ duration: 0.2 }}
              >
                <Typography
                  variant="h6"
                  sx={{
                    fontWeight: 700,
                    color: 'primary.main',
                    textAlign: 'center',
                  }}
                >
                  HunterBot
                </Typography>
              </motion.div>
            )}
          </AnimatePresence>
          <Tooltip title={isCollapsed ? 'Expand' : 'Collapse'}>
            <IconButton
              onClick={() => setIsCollapsed(!isCollapsed)}
              sx={{
                color: 'text.secondary',
                '&:hover': {
                  color: 'primary.main',
                  bgcolor: 'primary.light',
                },
                borderRadius: 2,
              }}
            >
              {isCollapsed ? <ChevronRightIcon className="h-5 w-5" /> : <ChevronLeftIcon className="h-5 w-5" />}
            </IconButton>
          </Tooltip>
        </Box>

        <Divider sx={{ my: 2, bgcolor: 'divider' }} />

        <List>
          {filteredMenuItems.map((item, index) => (
            <AnimatedContainer key={item.text} delay={index * 0.1}>
              <Tooltip title={isCollapsed ? item.text : ''} placement="right">
                <ListItem
                  button
                  component={Link}
                  to={item.path}
                  sx={{
                    borderRadius: 2,
                    mb: 0.5,
                    px: isCollapsed ? 2 : 3,
                    py: 1,
                    justifyContent: isCollapsed ? 'center' : 'flex-start',
                    backgroundColor: location.pathname === item.path ? 'primary.light' : 'transparent',
                    '&:hover': {
                      backgroundColor: 'primary.light',
                      '& .MuiListItemIcon-root': {
                        color: 'primary.main',
                      },
                    },
                    transition: 'all 0.2s',
                  }}
                >
                  <ListItemIcon
                    sx={{
                      color: location.pathname === item.path ? 'primary.main' : 'text.secondary',
                      minWidth: isCollapsed ? 'auto' : 40,
                      '&:hover': {
                        color: 'primary.main',
                      },
                    }}
                  >
                    {item.icon}
                  </ListItemIcon>
                  <AnimatePresence>
                    {!isCollapsed && (
                      <motion.div
                        initial={{ opacity: 0, x: -20 }}
                        animate={{ opacity: 1, x: 0 }}
                        exit={{ opacity: 0, x: -20 }}
                        transition={{ duration: 0.2 }}
                      >
                        <ListItemText
                          primary={item.text}
                          sx={{
                            color: location.pathname === item.path ? 'primary.main' : 'text.primary',
                            '& .MuiTypography-root': {
                              fontWeight: location.pathname === item.path ? 600 : 400,
                              fontSize: '0.95rem',
                            },
                          }}
                        />
                      </motion.div>
                    )}
                  </AnimatePresence>
                </ListItem>
              </Tooltip>
            </AnimatedContainer>
          ))}
        </List>
      </Box>
    </Drawer>
  );
};

export default Sidebar;
